parameters.jsCode:
const data = $input.first().json;

const metricMap = {
  avg_confidence: "平均信心值",
  execution_time_sec: "執行時間",
  total_boxes: "偵測框數",
  detected_images: "偵測到裂縫的影像數"
};

const sourceMap = {
  all: "全部來源",
  windows: "Windows",
  pi: "Raspberry Pi 5"
};

const typeMap = {
  trend: "趨勢分析",
  compare_models: "模型比較"
};

function fmtNum(value, digits = 4) {
  if (value === undefined || value === null || value === "") return "未提供";
  const n = Number(value);
  return Number.isFinite(n) ? n.toFixed(digits) : String(value);
}

// ============================================================
// Compare Models Formatter
// ============================================================
if (data.query_type === "compare_models") {
  const models = data.models || {};
  const gam = models.GAM || null;
  const sa = models.SA || null;

  let reply = "歷史分析結果\n\n";

  reply += "分析類型：模型比較\n\n";
  reply += `來源：${sourceMap[data.source] || data.source || "全部來源"}\n\n`;
  reply += `比較模型：GAM vs SA\n\n`;
  reply += `指標：${metricMap[data.metric] || data.metric || "平均信心值"}\n\n`;

  if (gam) {
    reply += "GAM：\n";
    reply += `平均信心值：${fmtNum(gam.avg_confidence)}\n`;
    reply += `平均執行時間：${fmtNum(gam.avg_execution_time_sec)} 秒\n`;
    reply += `平均偵測框數：${fmtNum(gam.avg_total_boxes)}\n`;
    reply += `總偵測次數：${gam.total_runs ?? "未提供"}\n`;
    reply += `總影像數：${gam.total_images ?? "未提供"}\n`;
    reply += `總偵測框數：${gam.total_boxes ?? "未提供"}\n\n`;
  } else {
    reply += "GAM：目前沒有可用紀錄\n\n";
  }

  if (sa) {
    reply += "SA：\n";
    reply += `平均信心值：${fmtNum(sa.avg_confidence)}\n`;
    reply += `平均執行時間：${fmtNum(sa.avg_execution_time_sec)} 秒\n`;
    reply += `平均偵測框數：${fmtNum(sa.avg_total_boxes)}\n`;
    reply += `總偵測次數：${sa.total_runs ?? "未提供"}\n`;
    reply += `總影像數：${sa.total_images ?? "未提供"}\n`;
    reply += `總偵測框數：${sa.total_boxes ?? "未提供"}\n\n`;
  } else {
    reply += "SA：目前沒有可用紀錄\n\n";
  }

  reply += "比較結論：\n";

  if (gam && sa) {
    if (gam.avg_confidence > sa.avg_confidence) {
      reply += "GAM 的平均信心值較高。\n";
    } else if (gam.avg_confidence < sa.avg_confidence) {
      reply += "SA 的平均信心值較高。\n";
    } else {
      reply += "GAM 與 SA 的平均信心值接近。\n";
    }

    if (gam.avg_execution_time_sec > sa.avg_execution_time_sec) {
      reply += "SA 的平均執行時間較短，速度較快。\n";
    } else if (gam.avg_execution_time_sec < sa.avg_execution_time_sec) {
      reply += "GAM 的平均執行時間較短，速度較快。\n";
    } else {
      reply += "GAM 與 SA 的平均執行時間接近。\n";
    }
  } else {
    reply += "目前 GAM 或 SA 的歷史紀錄不足，暫時無法完整比較。\n";
  }

  return [
    {
      json: {
        reply
      }
    }
  ];
}

// ============================================================
// Trend Formatter
// ============================================================

function formatTimestamp(ts) {
  if (!ts) return "未提供";

  const s = String(ts);

  if (/^\d{8}_\d{6}$/.test(s)) {
    return (
      s.substring(0, 4) + "-" +
      s.substring(4, 6) + "-" +
      s.substring(6, 8) + " " +
      s.substring(9, 11) + ":" +
      s.substring(11, 13) + ":" +
      s.substring(13, 15)
    );
  }

  if (s.includes("T")) {
    return s.replace("T", " ").substring(0, 19);
  }

  return s;
}

function getMetricValue(record, metric) {
  if (!record) return null;

  if (record[metric] !== undefined) {
    return record[metric];
  }

  if (metric === "execution_time_sec") {
    return record.execution_time_sec ?? record.flask_execution_time_sec ?? null;
  }

  return null;
}

function getTime(record) {
  return (
    record?.timestamp ||
    record?.created_at ||
    record?.time ||
    record?.datetime ||
    "未提供"
  );
}

let reply = "歷史分析結果\n\n";

reply += `分析類型：${typeMap[data.query_type] || data.query_type || data.type || "未提供"}\n\n`;
reply += `來源：${sourceMap[data.source] || data.source || "全部來源"}\n\n`;
reply += `模型：${data.model || "all"}\n\n`;
reply += `指標：${metricMap[data.metric] || data.metric || "未提供"}\n\n`;
reply += `資料筆數：${data.count || 0}\n\n`;

if (Array.isArray(data.trend_points) && data.trend_points.length > 0) {
  reply += `最近 ${data.trend_points.length} 筆紀錄：\n\n`;

  data.trend_points.forEach((point, index) => {
    const record = point.record || point;
    const value = getMetricValue(record, data.metric);

    reply += `${index + 1}.\n`;
    reply += `時間：${formatTimestamp(getTime(record))}\n`;
    reply += `設備：${point.device || record.device || "未提供"}\n`;
    reply += `模型：${point.model || record.model || data.model || "未提供"}\n`;
    reply += `${metricMap[data.metric] || data.metric || "指標值"}：${fmtNum(value)}\n\n`;
  });
}

reply += "趨勢分析：\n\n";

if (data.avg_value !== undefined) {
  reply += `平均值：${fmtNum(data.avg_value)}\n\n`;
}

if (data.max_value !== undefined) {
  reply += `最高值：${fmtNum(data.max_value)}\n\n`;
}

if (data.min_value !== undefined) {
  reply += `最低值：${fmtNum(data.min_value)}\n\n`;
}

if (data.first_value !== undefined) {
  reply += `起始值：${fmtNum(data.first_value)}\n\n`;
}

if (data.last_value !== undefined) {
  reply += `最新值：${fmtNum(data.last_value)}\n\n`;
}

if (data.delta !== undefined) {
  reply += `變化量：${fmtNum(data.delta)}\n\n`;
}

if (data.change_percent !== undefined) {
  reply += `變化百分比：${fmtNum(data.change_percent, 2)}%\n\n`;
}

if (data.direction) {
  let trendText = "持平";

  if (data.direction === "up") {
    trendText = "上升";
  } else if (data.direction === "down") {
    trendText = "下降";
  } else if (data.direction === "stable") {
    trendText = "穩定";
  }

  reply += `趨勢判斷：${trendText}\n\n`;
}

if (data.summary) {
  reply += `摘要：${data.summary}\n\n`;
}

return [
  {
    json: {
      reply
    }
  }
];

