(() => {

  const q = $json.query_type;
  const source = $json.source || "all";
  const limit = $json.limit || 5;

  const base = "http://host.docker.internal:5000";

  if (q === "latest") {
    return `${base}/history/latest?source=${source}`;
  }

  if (q === "recent") {
    return `${base}/history/recent?source=${source}&limit=${limit}`;
  }

  if (q === "stats") {
    return `${base}/history/stats?source=${source}`;
  }

  if (q === "best_confidence") {
    return `${base}/history/best-confidence?source=${source}`;
  }

  if (q === "fastest") {
    return `${base}/history/fastest?source=${source}`;
  }

  if (q === "clean") {
    return `${base}/history/clean?source=${source}`;
  }

  throw new Error(`Unsupported query_type: ${q}`);

})()
}}

parameters.jsCode:
const data = $input.first().json;

function formatTime(ts) {
  if (!ts) return "未提供";

  const s = String(ts);

  if (s.length === 15 && s.includes("_")) {
    const year = s.slice(0, 4);
    const month = s.slice(4, 6);
    const day = s.slice(6, 8);
    const hour = s.slice(9, 11);
    const min = s.slice(11, 13);
    const sec = s.slice(13, 15);

    return `${year}-${month}-${day} ${hour}:${min}:${sec}`;
  }

  return s;
}

function getRecord() {
  if (Array.isArray(data.records) && data.records.length > 0) {
    return data.records[0];
  }
  return null;
}

function formatRecord(title, r) {
  if (!r) return `${title}\n\n查無歷史紀錄。`;

  return (
    `${title}\n\n` +
    `偵測時間：${formatTime(r.timestamp)}\n` +
    `設備：${r.device || r.source || "未提供"}\n` +
    `模型：${r.model || "未提供"}\n` +
    `平均信心值：${r.avg_confidence ?? "未提供"}\n` +
    `總影像數：${r.total_images ?? "未提供"}\n` +
    `偵測到裂縫影像數：${r.detected_images ?? "未提供"}\n` +
    `總偵測框數：${r.total_boxes ?? "未提供"}\n` +
    `執行時間：${r.execution_time_sec ?? "未提供"} 秒`
  );
}

let reply = "";

if (data.query_type === "latest") {
  reply = formatRecord("最近一次偵測紀錄", getRecord());
}

else if (data.query_type === "recent") {
  const records = Array.isArray(data.records) ? data.records : [];
  const count = data.count ?? records.length;

  if (records.length === 0) {
    reply = "最近偵測紀錄\n\n查無歷史紀錄。";
  } else {
    reply = `最近 ${count} 次偵測紀錄\n\n`;

    records.forEach((r, i) => {
      reply +=
        `${i + 1}. 偵測時間：${formatTime(r.timestamp)}\n` +
        `設備：${r.device || r.source || "未提供"}\n` +
        `模型：${r.model || "未提供"}\n` +
        `平均信心值：${r.avg_confidence ?? "未提供"}\n` +
        `總影像數：${r.total_images ?? "未提供"}\n` +
        `偵測到裂縫影像數：${r.detected_images ?? "未提供"}\n` +
        `總偵測框數：${r.total_boxes ?? "未提供"}\n` +
        `執行時間：${r.execution_time_sec ?? "未提供"} 秒\n\n`;
    });

    reply = reply.trim();
  }
}

else if (data.query_type === "stats") {
  const deviceCount = data.device_count || {};
  const modelCount = data.model_count || {};

  reply =
    "歷史統計\n\n" +
    `平均信心值：${data.avg_confidence_overall ?? "未提供"}\n` +
    `平均執行時間：${data.avg_execution_time_sec ?? "未提供"} 秒\n\n` +
    "設備統計\n" +
    `Windows：${deviceCount.Windows ?? 0}\n` +
    `Raspberry Pi 5：${deviceCount["Raspberry Pi 5"] ?? 0}\n` +
    `Unknown：${deviceCount.unknown ?? 0}\n\n` +
    "模型統計\n" +
    `GAM：${modelCount.GAM ?? 0}\n` +
    `SA：${modelCount.SA ?? 0}`;
}

else if (data.query_type === "best_confidence") {
  reply = formatRecord("最高信心值紀錄", getRecord());
}

else if (data.query_type === "fastest") {
  reply = formatRecord("最快執行紀錄", getRecord());
}

else if (data.query_type === "clean" || data.query_type === "clean_history") {
  reply =
    "歷史紀錄清理完成\n\n" +
    `清理前紀錄數：${data.before_count ?? "未提供"}\n` +
    `清理後紀錄數：${data.after_count ?? "未提供"}\n` +
    `移除紀錄數：${data.removed_count ?? "未提供"}`;
}

else {
  reply = "無法辨識的歷史查詢類型。";
}

return [
  {
    json: {
      reply
    }
  }
];
